UPDATE
    member
SET
    userPhone=#{userPhone}
    , userEmail=#{userEmail}
WHERE
    userId = #{userId}

mapper.delete:
DELETE FROM cart
WHERE
    userId=#{userId}
    AND
    pOpNo=#{pOpNo}

mapper.update:
UPDATE
    cart
SET
    cCount=cCount + 1
    , cPrice=cPrice + #{cPrice}
WHERE
    userId=#{userId}
    AND
    pOpNo=#{pOpNo}

UPDATE
    cart
SET
    cCount=cCount - 1
    , cPrice=cPrice - #{cPrice}
WHERE
    userId=#{userId}
    AND
    pOpNo=#{pOpNo}

